private async getCurrentColorStyle(styleId?: number): Promise<IStyleColorBase | null> {
	if (!styleId) {
		return null;
	}

	const currentStyle = await this.styleColorsService.getStyleByStyleId({
		styleId: Number(styleId),
	});

	if (!currentStyle) {
		this.logger.warn('No style found', { styleId });
	}

	return currentStyle;
}

