			jest.spyOn(service as any, 'extractFeaturesRelatedFields').mockReturnValue({
				name: 'Test Product',
				manufacturer: 'Test Manufacturer',
			});

			jest.spyOn(service as any, 'saveStyleToDatabase').mockResolvedValue(undefined);

			openAIService.generateProductFeatures
				.mockResolvedValueOnce({
					error: "This model's maximum context length is 128000 tokens",
				})
