			jest.spyOn(service as any, 'saveStyleToDatabase').mockResolvedValue(undefined);

			openAIService.generateProductFeatures.mockResolvedValue({
				error: 'Network connection failed',
			});

			await expect(
				service.process({ style: testStyle, allCategories: [] }),
