import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { AlgoliaService } from '@modules/algolia/algolia.service';
import { CondensedFeaturesService } from '@modules/db/condensed-features/condensed-features.service';
import { ProductAnnualSalesService } from '@modules/db/product-annual-sales/product-annual-sales.service';
import { StylesService } from '@modules/db/styles/styles.service';
import { StylesHashService } from '@modules/db/styles-hash/styles-hash.service';
import { IStylesHashBase } from '@modules/db/styles-hash/types/styles-hash.base.interface';
import { MmsService } from '@modules/mms/mms.service';
import { OpenAIService } from '@modules/rest/open-ai/open-ai.service';
import { ProcessStyleService } from '@modules/rest/process-style/process-style.service';

import { compareHashes } from '@utils/compare-hashes.util';
import { hashFromObject } from '@utils/hash-from-object.unit';

import { STYLES_HASHING_ALGORITHM } from '@constants/common.constant';

import {
	MMSStyleToProcess,
	MMSStyleCategory,
	MMSAllStyleCategory,
} from '@interfaces/mms-style-to-process.interface';

jest.mock('@utils/compare-hashes.util');
jest.mock('@utils/hash-from-object.unit');
jest.mock('@utils/retry.util', () => ({
	withRetry: jest
		.fn()
		.mockImplementation(async ({ fn }: { fn: () => Promise<unknown> }) => await fn()),
}));
jest.mock('@utils/get-env-variable.util', () => ({
	getEnv: jest.fn().mockReturnValue('http://mock-host.com'),
}));
jest.mock('@utils/color-match.util', () => ({
	convertRGBToString: jest.fn(({ rgb }) => `R:${rgb.R},G:${rgb.G},B:${rgb.B}`),
}));

global.fetch = jest.fn();

const mockCompareHashes = compareHashes as jest.MockedFunction<typeof compareHashes>;
const mockHashFromObject = hashFromObject as jest.MockedFunction<typeof hashFromObject>;
const mockFetch = fetch as jest.MockedFunction<typeof fetch>;

const mockProductAnnualSalesService = {
	getPurchasesCountForLatestYear: jest.fn().mockResolvedValue(0),
};

describe('ProcessStyleService', () => {
	let service: ProcessStyleService;
	let condensedFeaturesService: jest.Mocked<CondensedFeaturesService>;
	let stylesHashService: jest.Mocked<StylesHashService>;
	let openAIService: jest.Mocked<OpenAIService>;
	let algoliaService: jest.Mocked<AlgoliaService>;
	let stylesService: jest.Mocked<StylesService>;
	let loggerDebugSpy: jest.SpyInstance;
	let loggerErrorSpy: jest.SpyInstance;
	let loggerWarnSpy: jest.SpyInstance;
	let loggerLogSpy: jest.SpyInstance;

	const mockCategory: MMSAllStyleCategory = {
		_id: 101,
		active: true,
		name: 'Test Category',
		parent_id: 100,
	};

	const mockStyleCategory: MMSStyleCategory = {
		id: 101,
		active: true,
		name: 'Test Category',
		parent_id: 100,
		default_quote_qty: 25,
	};

	const mockStyle: MMSStyleToProcess = {
		id: 2352352,
		name: 'Test Style',
		primary_category_id: 101,
		manufacturer: 'Test Manufacturer',
		min_qty: 25,
		status: 'active',
		primary_category: mockStyleCategory,
		categories: [mockStyleCategory],
		has_singles_enabled_colors: true,
		rating_count: 10,
		rating_score: '4.5',
		style_type: 'apparel',
		price_level: 1,
		product_type: 't-shirt',
		decoration_method: 'screen printing',
		features: 'comfortable, durable',
		general_comments: 'great for events',
		style_sizes: [{ name: 'S' }, { name: 'M' }, { name: 'L' }],
		colors: [
			{
				name: 'Red',
				id: 1,
				status: 'active',
				rbgs: [{ R: 255, G: 0, B: 0 }],
				image_url: 'http://example.com/red.jpg',
			},
			{
				name: 'Blue',
				id: 2,
				status: 'active',
				rbgs: [{ R: 0, G: 0, B: 255 }],
				image_url: 'http://example.com/blue.jpg',
			},
		],
		default_unit_prices: [
			{
				algorithm: 'default-2022-03-24',
				quantity: 100,
				price: '10.99',
			},
			{
				algorithm: 'volume',
				quantity: 500,
				price: '8.99',
			},
		],
		turntime: {
			id: 1,
			style_id: 2352352,
			rush: 3,
			standard: 7,
		},
	} as MMSStyleToProcess;

	const mockHashValue = 'mock-hash-abc123';
	const mockGeneratedFeatures = ['mocked-feature-1', 'mocked-feature-2'];

	beforeEach(async () => {
		const mockCondensedFeaturesService = {
			upsertCondensedFeature: jest.fn().mockResolvedValue(undefined),
			updateCondensedFeature: jest.fn().mockResolvedValue(undefined),
			getCondensedFeature: jest.fn().mockResolvedValue(null),
			deleteCondensedFeature: jest.fn(),
		};

		const mockStylesHashService = {
			getStyleHash: jest.fn(),
			updateHashValue: jest.fn().mockResolvedValue(undefined),
			createStyleHash: jest.fn().mockResolvedValue(undefined),
			deleteStyleHash: jest.fn(),
			checkHashChanged: jest.fn(),
		};

		const mockOpenAIService = {
			generateProductFeatures: jest
				.fn()
				.mockResolvedValue({ description: mockGeneratedFeatures }),
		};

		const mockAlgoliaService = {
			upsertObject: jest.fn().mockResolvedValue(undefined),
			deleteObject: jest.fn().mockResolvedValue(undefined),
			saveObjects: jest.fn().mockResolvedValue(undefined),
			deleteObjects: jest.fn().mockResolvedValue(undefined),
			searchObjects: jest.fn().mockResolvedValue([]),
		};

		const mockMmsService = {
			fetchStyles: jest.fn().mockResolvedValue({
				styles: [],
				total_entries: 0,
				total_pages: 1,
				current_page: 1,
				per_page: 25,
			}),
		};

		const mockStylesService = {
			saveCompleteStyle: jest.fn().mockResolvedValue(undefined),
		};

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				ProcessStyleService,
				{
					provide: ProductAnnualSalesService,
					useValue: mockProductAnnualSalesService,
				},
				{
					provide: CondensedFeaturesService,
					useValue: mockCondensedFeaturesService,
				},
				{
					provide: StylesHashService,
					useValue: mockStylesHashService,
				},
				{
					provide: OpenAIService,
					useValue: mockOpenAIService,
				},
				{
					provide: AlgoliaService,
					useValue: mockAlgoliaService,
				},
				{
					provide: MmsService,
					useValue: mockMmsService,
				},
				{
					provide: StylesService,
					useValue: mockStylesService,
				},
			],
		}).compile();

		service = module.get<ProcessStyleService>(ProcessStyleService);
		condensedFeaturesService = module.get(CondensedFeaturesService);
		stylesHashService = module.get(StylesHashService);
		openAIService = module.get(OpenAIService);
		algoliaService = module.get(AlgoliaService);
		stylesService = module.get(StylesService);

		loggerDebugSpy = jest
			.spyOn(Logger.prototype, 'debug')
			.mockImplementation(() => undefined);
		loggerErrorSpy = jest
			.spyOn(Logger.prototype, 'error')
			.mockImplementation(() => undefined);
		loggerWarnSpy = jest
			.spyOn(Logger.prototype, 'warn')
			.mockImplementation(() => undefined);
		loggerLogSpy = jest
			.spyOn(Logger.prototype, 'log')
			.mockImplementation(() => undefined);

		mockHashFromObject.mockReturnValue(mockHashValue);
		mockFetch.mockResolvedValue({
			ok: true,
			json: jest.fn().mockResolvedValue({
				styles: [],
				total_entries: '0',
				total_pages: '1',
				current_page: '1',
				per_page: '25',
			}),
		} as unknown as Response);

		jest.clearAllMocks();
	});

	afterEach(() => {
		jest.restoreAllMocks();
	});

	describe('process', () => {
		describe('when no stored hash exists', () => {
			beforeEach(() => {
				stylesHashService.getStyleHash.mockResolvedValue(null);
			});

			it('should generate features and save everything for new style', async () => {
				const result = await service.process({
					style: mockStyle,
					allCategories: [mockCategory],
				});

				expect(stylesHashService.getStyleHash).toHaveBeenCalledWith({
					styleId: mockStyle.id,
				});
				expect(openAIService.generateProductFeatures).toHaveBeenCalledWith({
					productInfo: mockStyle,
				});
				expect(condensedFeaturesService.upsertCondensedFeature).toHaveBeenCalledWith({
					data: { style_id: mockStyle.id, condensed_features: mockGeneratedFeatures },
				});
				expect(stylesHashService.createStyleHash).toHaveBeenCalledWith({
					data: {
						style_id: mockStyle.id,
						hash: mockHashValue,
						hashing_algorithm: STYLES_HASHING_ALGORITHM,
					},
				});
				expect(algoliaService.saveObjects).toHaveBeenCalled();
				expect(result).toBe(true);
